const input = $input.first().json;
const body = input.body || input; 
const headers = input.headers || {};

const str = k => (body && body[k] !== undefined && body[k] !== null) ? body[k].toString().trim() : '';

const num = k => {
  const value = body[k];
  if (value === undefined || value === null || value.toString().trim() === "") return null;
  const cleanValue = value.toString().replace(/[R$\s.]/g, '').replace(',', '.');
  const parsed = parseFloat(cleanValue);
  return isNaN(parsed) ? null : parsed;
};

const dte = k => {
  const value = body[k];
  if (value === undefined || value === null || value.toString().trim() === "") return null;
  return value;
};

const campos = {
  id_url: body.id_url || '',
  // Bloco 1: Identificação + Cônjuge
  nome: str('nome'),
  email: str('email'),
  telefone: str('telefone'),
  cpf: str('cpf'),
  nascimento: dte('nascimento'),
  endereco: str('endereco'),
  tem_filhos: str('tem_filhos'),
  filhos: Array.isArray(body.filhos) ? body.filhos : [],
  estado_civil: str('estado_civil'),
  nome_conjuge: str('nome_conjuge'),
  conjuge_renda_propria: str('conjuge_renda_propria'),
  profissao_conjuge: str('profissao_conjuge'),
  fiancas_compartilhadas: str('fiancas_compartilhadas'),

  // Bloco 2: Perfil Profissional (NOVO)
  tipo_atuacao: str('tipo_atuacao'),
  nome_empresa: str('nome_empresa'),
  segmento_empresa: str('segmento_empresa'),
  faturamento_medio: num('faturamento_medio'),
  sazonalidade: str('sazonalidade'),
  clareza_lucro: str('clareza_lucro'),
  tipo_retirada: str('tipo_retirada'),
  renda_mensal_clt: num('renda_mensal_clt'),
  profissao_clt: str('profissao_clt'),
  recebe_comissao: str('recebe_comissao'),

  // Bloco 3: Realidade Financeira
  mora_em: str('mora_em'),
  categorias_orcamento: str('categorias_orcamento'),
  patrimonio_total: num('patrimonio_total'),
  valor_aplicacoes: num('valor_aplicacoes'),
  tem_dividas: str('tem_dividas'),
  valor_dividas: num('valor_dividas'),
  tem_atrasos: str('tem_atrasos'),

  // Bloco 4, 5 e 6 permanecem similares, mas certifique-se de mapear os nomes corretos
  tem_aporte: str('tem_aporte'),
  valor_aporte: num('valor_aporte'),
  tipos_investimento: str('tipos_investimento'),
  perfil_investidor: str('perfil_investidor'),
  seguranca_familiar: str('seguranca_familiar'),
  tem_blindagem: str('tem_blindagem'),
  tem_seguros: str('tem_seguros'),
  quais_seguros: str('quais_seguros'),
  objetivo_curto: str('objetivo_curto'),
  objetivo_medio: str('objetivo_medio'),
  objetivo_longo: str('objetivo_longo'),
  hobbies: str('hobbies'),
  planejamento_valeria: str('planejamento_valeria')
};

const erros = [];
if (!campos.nome) erros.push('Nome é obrigatório.');

const data = new Date();
const agora = new Date(data.getTime() - (3 * 60 * 60 * 1000)).toISOString().replace('Z', '');

return [{ json: { ...campos, recebidoEm: agora, valido: erros.length === 0, erros } }];
